"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[6176],{5508:(e,t,l)=>{l.r(t),l.d(t,{data:()=>D});const D=JSON.parse('{"key":"v-fe574c80","path":"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F/%D0%BA%D0%BE%D1%81%D1%81-%D1%81%D1%83%D1%82%D1%8C-%D1%83%D0%BF%D1%80%D0%B0%D0%B2%D0%BB%D0%B5%D0%BD%D0%B8%D1%8F-%D0%B2-%D1%82%D1%80%D0%B0%D0%BD%D1%81%D1%84%D0%BE%D1%80%D0%BC%D0%B0%D1%86%D0%B8%D0%B8-%D0%B8%D0%BD%D1%84%D0%BE%D1%80%D0%BC%D0%B0%D1%86%D0%B8%D0%B8.html","title":"Суть управления в трансформации информации","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[{"level":2,"title":"2. Системные условия трансформации информации при взаимодействии персонала и средств автоматизации процесса","slug":"_2-системные-условия-трансформации-информации-при-взаимодеиствии-персонала-и-средств-автоматизации-процесса","link":"#_2-системные-условия-трансформации-информации-при-взаимодеиствии-персонала-и-средств-автоматизации-процесса","children":[]},{"level":2,"title":"3. Модели формирования объективных данных","slug":"_3-модели-формирования-объективных-данных","link":"#_3-модели-формирования-объективных-данных","children":[]}],"git":{"updatedTime":1730483869000},"filePathRelative":"глушковские-чтения/косс-суть-управления-в-трансформации-информации.md"}')},4035:(e,t,l)=>{l.r(t),l.d(t,{default:()=>f});var D=l(6252);const a=(0,D._)("h1",{id:"суть-управления-в-трансформации-информации",tabindex:"-1"},[(0,D._)("a",{class:"header-anchor",href:"#суть-управления-в-трансформации-информации","aria-hidden":"true"},"#"),(0,D.Uk)(" Суть управления в трансформации информации")],-1),n=(0,D._)("p",null,"Косс В. А.",-1),o=(0,D.uE)('<blockquote><p>Суть управления и связи состоит в передаче, хранении и трансформации информации.</p></blockquote><p>В. М. Глушков</p><p>## 1. Введение</p><p>Важнейшим условием системной гармонии любой организационной (общественной) системы является соответствие системы управления потребностям объекта управления. Материал доклада направлен на освещение проблем трансформации информации при взаимодействии персонала и средств автоматизации процесса управления.</p><h2 id="_2-системные-условия-трансформации-информации-при-взаимодеиствии-персонала-и-средств-автоматизации-процесса" tabindex="-1"><a class="header-anchor" href="#_2-системные-условия-трансформации-информации-при-взаимодеиствии-персонала-и-средств-автоматизации-процесса" aria-hidden="true">#</a> 2. Системные условия трансформации информации при взаимодействии персонала и средств автоматизации процесса</h2><p>Основными системообразующими характеристиками организационных и общественных систем являются ресурсы, их пространственная организация, регламент взаимодействия и функционирования для достижения предназначения (целевой функции) системы.</p><p>При этом персонал системы имеет двойственное предназначение. <strong>Как ресурс системы</strong> он реализует свои производственные функции и навыки, а <strong>как носитель интеллекта</strong> персонал имеет <strong>исключительное</strong> свойство — быть носителем и интерпретатором информации:</p><ul><li><p>о трансформации предназначения системы в полномочия должностных лиц (должностные обязанности, производственные задачи и задания);</p></li><li><p>о состоянии ресурсов, их пространственной организации, реализации процедур технологического цикла их взаимодействия с ресурсами всей системы и окружающей среды, а также информации о свойствах системы, позволяющих ей реализовать свое предназначение и сохранять устойчивость. Также персонал должен оценивать степень достижения поставленных задач, устойчивость системы, меру ответственности персонала за реализацию функций и навыков.</p></li></ul><p>Персонал принимает непосредственное участие в трансформации информации о задании в информацию о достижении результата. Такая трансформация составляет нисходящую ветвь процедур цикла управления [1-2]. На восходящей ветви процедур управления происходит аналитическая трансформация информации о результатах в оценку эффективности работы системы, ее устойчивости и персонального вклада каждого должностного лица.</p><p>Оценка вклада персонала имеет моральную и материальную составляющую. Стремление должностного лица сохранить благополучие и обеспечить себе возможность карьерного роста приводит к преимущественной мотивации на преувеличение личного или коллективного вклада. Таким образом, в систему управления внедряется существенная ложь или неопределенность (отсутствие информации, ее неактуальность, частичное искажение). Мотивацией для искажения информации могут служить также политические предпочтения и корыстные устремления, вплоть до криминальных целей. Как решать проблему поддержания достаточной актуальности и достоверности средствами автоматизации? Мы пытаемся на этой конференции осознать конструкторские прозрения в проекте ОГАС.</p><h2 id="_3-модели-формирования-объективных-данных" tabindex="-1"><a class="header-anchor" href="#_3-модели-формирования-объективных-данных" aria-hidden="true">#</a> 3. Модели формирования объективных данных</h2><blockquote><p>« Молітесь Богові одному , молітесь правді на землі ...»</p></blockquote><p>Т. Шевченко</p><p>Вот несколько пророческих прозрений основателя отечественной кибернетики:</p><p>«Со временем, информационные средства страны будут объединены в единую автоматическую государственную систему, обеспечивающую сбор и переработку информации с целью управления всеми областями народного хозяйства»<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup>. «Сложные вычислительные системы будут развиваться в нескольких направлениях<sup class="footnote-ref"><a href="#fn2" id="fnref2">[2]</a></sup>: построение единой государственной сети вычислительных центров; машины нижнего уровня будут работать с объектом в реальном времени; выделение специализированных систем для обработки экспериментальных данных».</p><p>Современные возможности по организации виртуальных серверов и сетей, вычислительных комплексов типа ГРИД прекрасно вписываются в пожелания авторов проекта ОГАС. Технологии организации хранилищ данных позволяют реализовать контроль их актуальности, согласованности и достоверности, в том числе, и через приборный мониторинг процессов функционирования систем. Для объективного мониторинга процессов имеются все необходимые инструменты и технологии, требуется лишь стремление к эффективному управлению и исключение субъективной составляющей искажения информации. Достаточно вспомнить позицию В. М. Глушкова: «Основная задача внедрения ЭВМ в сферу учета, планирования и управления экономикой заключается не в простой замене ручного труда, а в <strong>коренном изменении самих методов</strong> управленческого труда»<sup class="footnote-ref"><a href="#fn3" id="fnref3">[3]</a></sup>. На схеме представлены модели формирования единого хранилища данных. Иерархическая модель, существующая сейчас, несет в себе наибольшие возможности для влияния персонала на искажение информации. Параллельная модель снижает субъективную составляющую тем больше, чем больше процессов охвачено аппаратным мониторингом в реальном времени.</p><figure><img src="/images/глушковские-чтения/косс-суть-управления-в-трансформации-информации.png" alt="" tabindex="0"><figcaption></figcaption></figure><p>## 4. Выводы</p><p>Процесс проектирования ошибочно воспринимают как процесс «придумывания» создаваемой системы. Современное научное творчество только тогда станет эффективным, когда проектировщики поймут, что процесс функционального проектирования любой системы есть попытка познать замысел Творца, последовательно реализующего программу жизненного цикла человечества, а процесс инженерной реализации функций создаваемой системы есть процесс сотворчества с Творцом, где люди, в меру своей сознательности, пытаются реализовать замысел Творца наилучшим образом.</p><p>## Библиография</p>',20),r={href:"http://conf.atsukr.org.ua/files/conf_dir_1/koss_sppr05.pdf",target:"_blank",rel:"noopener noreferrer"},s=(0,D._)("li",null,[(0,D._)("p",null,"Косс В.А. Анализ структурной модели государства с позиции новой кибернетики \\ Теория и практика управления. – 2005.- No7(24). С.9-13.")],-1),p=(0,D.uE)('<hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p>В. М. Глушков. Вестник АН СССР. –1962.-№4 <a href="#fnref1" class="footnote-backref">↩︎</a></p></li><li id="fn2" class="footnote-item"><p>В. М. Глушков. Механизация и автоматизация управления. –Киев, 1967.-№2 <a href="#fnref2" class="footnote-backref">↩︎</a></p></li><li id="fn3" class="footnote-item"><p>В. М. Глушков. Препринт. Издательство ИК АН УССР, 1969 <a href="#fnref3" class="footnote-backref">↩︎</a></p></li></ol></section>',2),i={},f=(0,l(3744).Z)(i,[["render",function(e,t){const l=(0,D.up)("RouterLink"),i=(0,D.up)("ExternalLinkIcon");return(0,D.wg)(),(0,D.iD)("div",null,[a,n,(0,D._)("p",null,[(0,D.Uk)("Из материалов конференции "),(0,D.Wm)(l,{to:"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F.html"},{default:(0,D.w5)((()=>[(0,D.Uk)("«Глушковские чтения»")])),_:1}),(0,D.Uk)(" 2014 года.")]),o,(0,D._)("ol",null,[(0,D._)("li",null,[(0,D._)("p",null,[(0,D.Uk)("Косс В.А. "),(0,D._)("a",r,[(0,D.Uk)("Структурная модель цикла управления с позиции новой кибернетики для ее реализации в информационных системах"),(0,D.Wm)(i)]),(0,D.Uk)(".")])]),s]),p])}]])}}]);